SELECT 
FROM supplier_products

    AND status != 'deleted'
    AND id = #{id, jdbcType=BIGINT}
    AND supplier_id = #{supplierId, jdbcType=BIGINT}
    AND name = #{name, jdbcType=VARCHAR}
    AND images = #{images, jdbcType=VARCHAR}
    AND category_id = #{categoryId, jdbcType=BIGINT}
    AND category = #{category, jdbcType=VARCHAR}
    AND description = #{description, jdbcType=VARCHAR}
    AND material = #{material, jdbcType=VARCHAR}
    AND color = #{color, jdbcType=VARCHAR}
    AND size = #{size, jdbcType=VARCHAR}
    AND model = #{model, jdbcType=VARCHAR}
    AND style = #{style, jdbcType=VARCHAR}
    AND price = #{price, jdbcType=DECIMAL}
    AND stock = #{stock, jdbcType=INTEGER}
    AND spot_stock = #{spotStock, jdbcType=INTEGER}
    AND presale_cycle_days = #{presaleCycleDays, jdbcType=INTEGER}
    AND custom_cycle_days = #{customCycleDays, jdbcType=INTEGER}
    AND min_order_quantity = #{minOrderQuantity, jdbcType=INTEGER}
    AND delivery_areas = #{deliveryAreas, jdbcType=VARCHAR}
    AND package_info = #{packageInfo, jdbcType=VARCHAR}
    AND support_installation = #{supportInstallation, jdbcType=BOOLEAN}
    AND status = #{status, jdbcType=VARCHAR}
    AND review_status = #{reviewStatus, jdbcType=VARCHAR}
    AND created_at = #{createdAt, jdbcType=TIMESTAMP}
    AND updated_at = #{updatedAt, jdbcType=TIMESTAMP}

ORDER BY id DESC

SELECT 
FROM supplier_products

    AND status = 'active'
    AND review_status = 'approved'
    AND stock > 0

        AND (name LIKE CONCAT('%', #{keyword}, '%') OR material LIKE CONCAT('%', #{keyword}, '%') OR style LIKE CONCAT('%', #{keyword}, '%') OR category LIKE CONCAT('%', #{keyword}, '%'))

    AND category_id = #{categoryId, jdbcType=BIGINT}
    AND category = #{category, jdbcType=VARCHAR}
    AND price >= #{minPrice, jdbcType=DECIMAL}
    AND price <= #{maxPrice, jdbcType=DECIMAL}
    AND material = #{material, jdbcType=VARCHAR}
    AND style = #{style, jdbcType=VARCHAR}
    AND support_installation = #{supportInstallation, jdbcType=BOOLEAN}

ORDER BY updated_at DESC, id DESC

    LIMIT #{offset, jdbcType=INTEGER}, #{pageSize, jdbcType=INTEGER}

SELECT COUNT(1)
FROM supplier_products

    AND status = 'active'
    AND review_status = 'approved'
    AND stock > 0

        AND (name LIKE CONCAT('%', #{keyword}, '%') OR material LIKE CONCAT('%', #{keyword}, '%') OR style LIKE CONCAT('%', #{keyword}, '%') OR category LIKE CONCAT('%', #{keyword}, '%'))

    AND category_id = #{categoryId, jdbcType=BIGINT}
    AND category = #{category, jdbcType=VARCHAR}
